func computeVelocity(db *sql.DB, threshold float64, sinceDate string) ([]map[string]any, error) {
	rows, err := db.Query(`SELECT sku, asin, purchase_date, quantity FROM order_details WHERE purchase_date >= ?`, sinceDate)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	type series struct {
		asin string
		days map[string]int
	}
	bySKU := map[string]*series{}
	for rows.Next() {
		var sku, asin, date sql.NullString
		var qty int
		if err := rows.Scan(&sku, &asin, &date, &qty); err != nil {
			return nil, err
		}
		key := sku.String
		if key == "" {
			continue
		}
		if bySKU[key] == nil {
			bySKU[key] = &series{asin: asin.String, days: map[string]int{}}
		}
		day := strings.Split(date.String, "T")[0]
		bySKU[key].days[day] += qty
	}
	var out []map[string]any
	for sku, s := range bySKU {
		last7, last30 := sumRecent(s.days, 7), sumRecent(s.days, 30)
		avg7, avg30 := float64(last7)/7, float64(last30)/30
		trend := "flat"
		if avg7 > avg30*1.2 {
			trend = "accelerating"
		} else if avg7 < avg30*0.8 {
			trend = "decelerating"
		}
		z := velocityZScore(s.days)
		anomaly := math.Abs(z) >= threshold
		typ := ""
		if anomaly {
			if z < 0 {
				typ = "sudden_drop"
			} else {
				typ = "spike"
			}
		}
		out = append(out, map[string]any{"sku": sku, "asin": s.asin, "units_last_7d": last7, "units_last_30d": last30, "avg_daily_7d": avg7, "avg_daily_30d": avg30, "trend": trend, "anomaly_detected": anomaly, "anomaly_type": typ})
	}
	sort.Slice(out, func(i, j int) bool {
		return numericField(out[i], "units_last_30d") > numericField(out[j], "units_last_30d")
	})
	return out, rows.Err()
}

func computeReturnRates(db *sql.DB, minReturnRate float64, sinceDate string) ([]map[string]any, error) {
	rows, err := db.Query(`WITH order_rollup AS (
			SELECT sku, COALESCE(MAX(asin), '') AS asin, SUM(quantity) AS sold
			FROM order_details WHERE purchase_date >= ? GROUP BY sku
		), return_rollup AS (
			SELECT sku, SUM(quantity) AS returned, COALESCE(MAX(reason), '') AS reason, COALESCE(MAX(customer_comments), '') AS comments
			FROM returns_data WHERE return_date >= ? GROUP BY sku
		)
		SELECT o.sku, o.asin, o.sold, COALESCE(r.returned,0), COALESCE(r.reason, ''), COALESCE(r.comments, '')
		FROM order_rollup o LEFT JOIN return_rollup r ON r.sku=o.sku`, sinceDate, sinceDate)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var sku, asin, reason, comments string
		var sold, returned int
		if err := rows.Scan(&sku, &asin, &sold, &returned, &reason, &comments); err != nil {
			return nil, err
		}
		rate := pct(float64(returned), float64(sold))
		if minReturnRate > 0 && rate < minReturnRate {
			continue
		}
		qualityPct, listingPct := classifyReturnReason(reason)
		out = append(out, map[string]any{"sku": sku, "asin": asin, "units_sold": sold, "units_returned": returned, "return_rate_pct": rate, "top_reason": reason, "quality_issue_pct": qualityPct, "listing_accuracy_pct": listingPct, "customer_comments_sample": truncate(comments, 160)})
	}
	return out, rows.Err()
}

func sumRecent(days map[string]int, n int) int {
	total := 0
	now := time.Now().UTC()
	for i := 0; i < n; i++ {
		total += days[now.AddDate(0, 0, -i).Format("2006-01-02")]
	}
	return total
}

func velocityZScore(days map[string]int) float64 {
	if len(days) < 8 {
		return 0
	}
	now := time.Now().UTC()
	today := now.Format("2006-01-02")
	latestKey := now.AddDate(0, 0, -1).Format("2006-01-02")
	latest, ok := days[latestKey]
	if !ok {
		return 0
	}
	var vals []float64
	for day, v := range days {
		if day == today || day == latestKey {
			continue
		}
		vals = append(vals, float64(v))
	}
	if len(vals) < 2 {
		return 0
	}
	latestVal := float64(latest)
	mean := 0.0
	for _, v := range vals {
		mean += v
	}
	mean /= float64(len(vals))
	var variance float64
	for _, v := range vals {
		variance += (v - mean) * (v - mean)
	}
	std := math.Sqrt(variance / float64(len(vals)))
	return safeDiv(latestVal-mean, std)
}

func classifyReturnReason(reason string) (float64, float64) {
	reason = strings.ToLower(reason)
	switch {
	case strings.Contains(reason, "defective"), strings.Contains(reason, "damaged"), strings.Contains(reason, "quality"):
		return 100, 0
	case strings.Contains(reason, "description"), strings.Contains(reason, "wrong"), strings.Contains(reason, "not as"):
		return 0, 100
	default:
		return 0, 0
	}
}

func safeDiv(n, d float64) float64 {
	if d == 0 {
		return 0
	}
	return n / d
}
